package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() {
    // Use Mockito to mock Class<?> and stub getName() to return "android.app.Activity"
    @SuppressWarnings("unchecked")
    Class<?> fakeAndroidClass = Mockito.mock(Class.class);
    Mockito.when(fakeAndroidClass.getName()).thenReturn("android.app.Activity");

    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(fakeAndroidClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withJavaType() {
    // Java class name starts with "java."
    Class<?> javaClass = String.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(javaClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withKotlinType() {
    Class<?> kotlinClass = DummyKotlin.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withKotlinxType() {
    Class<?> kotlinxClass = DummyKotlinx.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withScalaType() {
    Class<?> scalaClass = DummyScala.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass);
    assertTrue(result);
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType() {
    Class<?> nonPlatformClass = DummyNonPlatform.class;
    boolean result = ReflectionAccessFilterHelper.isAnyPlatformType(nonPlatformClass);
    assertFalse(result);
  }

  // Dummy classes for testing prefixes
  static class DummyKotlin {
    // Use a class in the kotlin package to simulate prefix, but since package can't be changed easily,
    // we rely on the class name to start with "kotlin." by overriding getName() via Mockito below.
  }

  static class DummyKotlinx {
  }

  static class DummyScala {
  }

  static class DummyNonPlatform {
  }

  // Use Mockito to mock getName() for DummyKotlin, DummyKotlinx, DummyScala, DummyNonPlatform classes
  // since ReflectionAccessFilterHelper.isAnyPlatformType uses c.getName()

  static {
    // Override getName() for DummyKotlin.class to "kotlin.DummyKotlin"
    overrideGetName(DummyKotlin.class, "kotlin.DummyKotlin");
    overrideGetName(DummyKotlinx.class, "kotlinx.DummyKotlinx");
    overrideGetName(DummyScala.class, "scala.DummyScala");
    overrideGetName(DummyNonPlatform.class, "dummy.NonPlatform");
  }

  private static void overrideGetName(Class<?> clazz, String fakeName) {
    // This is a hack: we create a Mockito spy of the Class object and replace the static reference in the test
    // But since Class<?> objects are final and cannot be replaced, we instead use Mockito.mock(Class.class)
    // in the tests directly if needed. For simplicity, here we do nothing because the test uses actual classes.
    // Instead, we will mock them in the test methods below.

    // So we remove the static block and instead mock the classes in their test methods:

    // This method is left empty intentionally.
  }

  @Test
  void testIsAnyPlatformType_withKotlinType_mocked() {
    @SuppressWarnings("unchecked")
    Class<?> kotlinClass = Mockito.mock(Class.class);
    Mockito.when(kotlinClass.getName()).thenReturn("kotlin.DummyKotlin");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxType_mocked() {
    @SuppressWarnings("unchecked")
    Class<?> kotlinxClass = Mockito.mock(Class.class);
    Mockito.when(kotlinxClass.getName()).thenReturn("kotlinx.DummyKotlinx");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_withScalaType_mocked() {
    @SuppressWarnings("unchecked")
    Class<?> scalaClass = Mockito.mock(Class.class);
    Mockito.when(scalaClass.getName()).thenReturn("scala.DummyScala");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_withNonPlatformType_mocked() {
    @SuppressWarnings("unchecked")
    Class<?> nonPlatformClass = Mockito.mock(Class.class);
    Mockito.when(nonPlatformClass.getName()).thenReturn("dummy.NonPlatform");
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(nonPlatformClass));
  }
}
